mapper.select:
select o.outbound_id, o.outbound_date, o.outbound_request_date, o.outbound_status, o.outbound_amount, p.product_name, o.reject_reason_message
from outbound_table o
    join product p on o.product_id = p.product_id
where outbound_status = #{status}
LIMIT #{limit} OFFSET #{offset}

select admin_id
from admin_table
where user_id = #{userId}
